import{M as e,d as t,h as n}from"./chunks/runtime-core.esm-bundler.Di_optew.js";import{t as r}from"./chunks/plugin-vue_export-helper.B_ZXV7eh.js";var i=JSON.parse(`{"title":"SSR Options","description":"","frontmatter":{},"headers":[],"relativePath":"config/ssr-options.md","filePath":"config/ssr-options.md"}`),a={name:`config/ssr-options.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /config\\ssr-options.md for this page in Markdown format</div><h1 id="ssr-options" tabindex="-1">SSR Options <a class="header-anchor" href="#ssr-options" aria-label="Permalink to “SSR Options”">​</a></h1><p>Unless noted, the options in this section are applied to both dev and build.</p><h2 id="ssr-external" tabindex="-1">ssr.external <a class="header-anchor" href="#ssr-external" aria-label="Permalink to “ssr.external”">​</a></h2><ul><li><strong>Type:</strong> <code>string[] | true</code></li><li><strong>Related:</strong> <a href="/guide/ssr#ssr-externals">SSR Externals</a></li></ul><p>Externalize the given dependencies and their transitive dependencies for SSR. By default, all dependencies are externalized except for linked dependencies (for HMR). If you prefer to externalize the linked dependency, you can pass its name to this option.</p><p>If <code>true</code>, all dependencies including linked dependencies are externalized.</p><p>Note that the explicitly listed dependencies (using <code>string[]</code> type) will always take priority if they&#39;re also listed in <code>ssr.noExternal</code> (using any type).</p><h2 id="ssr-noexternal" tabindex="-1">ssr.noExternal <a class="header-anchor" href="#ssr-noexternal" aria-label="Permalink to “ssr.noExternal”">​</a></h2><ul><li><strong>Type:</strong> <code>string | RegExp | (string | RegExp)[] | true</code></li><li><strong>Related:</strong> <a href="/guide/ssr#ssr-externals">SSR Externals</a></li></ul><p>Prevent listed dependencies from being externalized for SSR, which they will get bundled in build. By default, only linked dependencies are not externalized (for HMR). If you prefer to externalize the linked dependency, you can pass its name to the <code>ssr.external</code> option.</p><p>If <code>true</code>, no dependencies are externalized. However, dependencies explicitly listed in <code>ssr.external</code> (using <code>string[]</code> type) can take priority and still be externalized. If <code>ssr.target: &#39;node&#39;</code> is set, Node.js built-ins will also be externalized by default.</p><p>Note that if both <code>ssr.noExternal: true</code> and <code>ssr.external: true</code> are configured, <code>ssr.noExternal</code> takes priority and no dependencies are externalized.</p><h2 id="ssr-target" tabindex="-1">ssr.target <a class="header-anchor" href="#ssr-target" aria-label="Permalink to “ssr.target”">​</a></h2><ul><li><strong>Type:</strong> <code>&#39;node&#39; | &#39;webworker&#39;</code></li><li><strong>Default:</strong> <code>node</code></li></ul><p>Build target for the SSR server.</p><h2 id="ssr-resolve-conditions" tabindex="-1">ssr.resolve.conditions <a class="header-anchor" href="#ssr-resolve-conditions" aria-label="Permalink to “ssr.resolve.conditions”">​</a></h2><ul><li><strong>Type:</strong> <code>string[]</code></li><li><strong>Default:</strong> <code>[&#39;module&#39;, &#39;node&#39;, &#39;development|production&#39;]</code> (<code>defaultServerConditions</code>) (<code>[&#39;module&#39;, &#39;browser&#39;, &#39;development|production&#39;]</code> (<code>defaultClientConditions</code>) for <code>ssr.target === &#39;webworker&#39;</code>)</li><li><strong>Related:</strong> <a href="./shared-options#resolve-conditions">Resolve Conditions</a></li></ul><p>These conditions are used in the plugin pipeline, and only affect non-externalized dependencies during the SSR build. Use <code>ssr.resolve.externalConditions</code> to affect externalized imports.</p><h2 id="ssr-resolve-externalconditions" tabindex="-1">ssr.resolve.externalConditions <a class="header-anchor" href="#ssr-resolve-externalconditions" aria-label="Permalink to “ssr.resolve.externalConditions”">​</a></h2><ul><li><strong>Type:</strong> <code>string[]</code></li><li><strong>Default:</strong> <code>[&#39;node&#39;]</code></li></ul><p>Conditions that are used during ssr import (including <code>ssrLoadModule</code>) of externalized direct dependencies (external dependencies imported by Vite).</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>When using this option, make sure to run Node with <a href="https://nodejs.org/docs/latest/api/cli.html#-c-condition---conditionscondition" target="_blank" rel="noreferrer"><code>--conditions</code> flag</a> with the same values in both dev and build to get a consistent behavior.</p><p>For example, when setting <code>[&#39;node&#39;, &#39;custom&#39;]</code>, you should run <code>NODE_OPTIONS=&#39;--conditions custom&#39; vite</code> in dev and <code>NODE_OPTIONS=&quot;--conditions custom&quot; node ./dist/server.js</code> after build.</p></div><h2 id="ssr-resolve-mainfields" tabindex="-1">ssr.resolve.mainFields <a class="header-anchor" href="#ssr-resolve-mainfields" aria-label="Permalink to “ssr.resolve.mainFields”">​</a></h2><ul><li><strong>Type:</strong> <code>string[]</code></li><li><strong>Default:</strong> <code>[&#39;module&#39;, &#39;jsnext:main&#39;, &#39;jsnext&#39;]</code></li></ul><p>List of fields in <code>package.json</code> to try when resolving a package&#39;s entry point. Note this takes lower precedence than conditional exports resolved from the <code>exports</code> field: if an entry point is successfully resolved from <code>exports</code>, the main field will be ignored. This setting only affects non-externalized dependencies.</p>`,26)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};